@end

@implementation WBVAppRemotePushManager

+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBVAppRemotePushManager alloc] init];
    });
    return instance;
