#pragma mark - PushKit Registration

- (void)doPKPushRegistryForVapp:(WBVAppModel*)vapp {
    void (^blk)(id, SEL, NSSet<PKPushType> *, IMP orig) = ^(id pkPushRegistry, SEL sel, NSSet<PKPushType> *desiredPushTypes, IMP orig) {
        self.pkPushRegistryDelegate = [pkPushRegistry delegate];
        PKPushRegistry_setDesiredPushTypes_fp fp = (PKPushRegistry_setDesiredPushTypes_fp)orig;
        if (fp == NULL) {
            NSLog(@"doPKPushRegistryForVapp:fp is NULL, cannot proceed with registration.");
            return;
        }
        fp(pkPushRegistry, sel, desiredPushTypes);
    };
    oaa_register_one_func_for_PKPushRegistry_setDesiredPushTypes_(blk);
}


@end
