            CGFloat adWidth = [UIScreen mainScreen].bounds.size.width;
            [model.mediation.canvasView mas_makeConstraints:^(MASConstraintMaker *make) {
                make.bottom.equalTo(self.view).offset(ZOOM(700));
                make.centerX.equalTo(self.view);
                make.width.mas_equalTo(adWidth);
                make.height.mas_equalTo(adWidth * 0.25);
            }];
        }
    }
