@implementation WBBenefitManager

+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBBenefitManager alloc] init];
    });
    return instance;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        self.currentBenefit = WBSettingManager.sharedManager.Benefit;
        self.currentBenefitSupport = WBSettingManager.sharedManager.BenefitSupport;
        [NSNotificationCenter.defaultCenter addObserverForName:WBAccountStatusChangedNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull note) {
            self.currentBenefit = WBSettingManager.sharedManager.Benefit;
            self.currentBenefitSupport = WBSettingManager.sharedManager.BenefitSupport;
        }];
    }
    return self;
}


#pragma mark - handle switch benefit function

- (BOOL)handleSwitchBenefitFunction:(WBUserBenefit)function target:(BOOL)target vapp:(WBVAppModel *)vapp {
    WBUserBenefitFunctionSwitchResult switchResult = WBUserBenefitFunctionSwitchResultOpenSuccess;
    WBUserBenefitFunctionSwitchResult (^evaluateVipEligibility)(void) = ^WBUserBenefitFunctionSwitchResult{
        if (!WBSettingManager.sharedManager.IsVIP) {    // 非会员
            return WBUserBenefitFunctionSwitchResultOpenErrorNotVip;
        } else if ((self.currentBenefit & function) == 0) { // 会员，但不包含此权益
            return WBUserBenefitFunctionSwitchResultOpenErrorVipNotHas;
        } else if ((self.currentBenefitSupport & function) == 0) {  // 会员，但不支持此权益
            return WBUserBenefitFunctionSwitchResultOpenErrorVipNotSupport;
        }
        return WBUserBenefitFunctionSwitchResultOpenSuccess;
    };

    if (!target) {  // 关闭功能
        switchResult = WBUserBenefitFunctionSwitchResultCloseSuccess;
    } else {
        if (WBSettingManager.sharedManager.BenefitTrialProperties.count > 0) {
            NSDictionary *matchedDict = nil;
            for (NSDictionary *dict in WBSettingManager.sharedManager.BenefitTrialProperties) {
                NSInteger bit = [dict[@"benefitBit"] integerValue];
                if (bit == (NSInteger)function) {
                    matchedDict = dict;
                    break;
                }
            }
            if (matchedDict) {
                id trialTimesObj = matchedDict[@"trialTimes"];
                if (trialTimesObj && trialTimesObj != [NSNull null]) {
                    NSInteger times = [WBSettingManager.sharedManager trialUsageTimesForBenefitBit:(NSInteger)function];
                    if (times <= 0) {
                        switchResult = evaluateVipEligibility();
                    }
                } else {
                    id descObj = matchedDict[@"desc"];
                    if (!descObj) {
                        switchResult = evaluateVipEligibility();
                    }
                }
            } else {
                switchResult = evaluateVipEligibility();
            }
        } else {
            switchResult = evaluateVipEligibility();
        }
    }
    NSInteger vid = vapp ? vapp.vid : 0;
    [self reportOpenBenefitFunctionEventWithVapp:vid function:function result:switchResult];
    return (switchResult == WBUserBenefitFunctionSwitchResultOpenSuccess || switchResult == WBUserBenefitFunctionSwitchResultCloseSuccess);
}

- (BOOL)consumeUsageOnceForBenefitBit:(NSInteger)bit {
    NSArray *arr = WBSettingManager.sharedManager.BenefitTrialProperties;
    if (arr.count <= 0) return NO;
    NSDictionary *matched = nil;
    for (NSDictionary *dict in arr) {
        NSInteger b = [dict[@"benefitBit"] integerValue];
        if (b == bit) {
            matched = dict;
            break;
        }
    }
    if (!matched) return NO;
    id trialTimesObj = matched[@"trialTimes"];
    if (trialTimesObj && trialTimesObj != [NSNull null]) {
        NSInteger times = [WBSettingManager.sharedManager trialUsageTimesForBenefitBit:bit];
        if (times <= 0) return NO;
        [WBSettingManager.sharedManager setTrialUsageTimes:(times - 1) forBenefitBit:bit];
        return YES;
    }
    return YES;
}

- (void)reportOpenBenefitFunctionEventWithVapp:(NSInteger)vid function:(WBUserBenefit)function result:(WBUserBenefitFunctionSwitchResult)result {
    NSMutableDictionary *data = [NSMutableDictionary dictionary];
    data[@"vid"] = @(vid);
    data[@"function"] = @(function);
    data[@"result"] = @(result);

    [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeUserSwitchBenefitFunction data:data defaultHandler:nil];
}


#pragma mark - Functions Toggle (Shared)

// 消息推送开关 (首页/设置页复用)
- (void)toggleNotificationForVapp:(WBVAppModel *)vapp
                         presenter:(UIViewController *)presenter
                         setSwitch:(void(^)(BOOL on, BOOL animated))setSwitch {
    if (WBVAppManager.sharedManager.myApps.count <= 0) {
        if (setSwitch) setSwitch(NO, YES);
        UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"提醒" message:@"请先安装您的第一个应用后再来开启吧" preferredStyle:UIAlertControllerStyleAlert];
        [alert addAction:[UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil]];
        UIViewController *vc = presenter ?: [WBAppManager getUIApplicationRootViewController];
        [vc presentViewController:alert animated:YES completion:nil];
        return;
    }

    BOOL isTurningOn = !vapp.featureStatusInfo.isNotificationSwitchOn;
    BOOL canSwitch = [self handleSwitchBenefitFunction:WBUserBenefitNotification target:isTurningOn vapp:vapp];
    if (!canSwitch) {
        if (setSwitch) setSwitch(NO, YES);
        return;
    }

    void (^toggleNotificationBlock)(BOOL) = ^(BOOL enable) {
        [WBNetworkManager.defaultManager connectNotification:vapp.bundleId isOn:!enable callback:^(id _Nullable json, NSError *_Nullable error) {
            dispatch_async(dispatch_get_main_queue(), ^{
                if (error) {
                    vapp.featureStatusInfo.isNotificationSwitchOn = !enable;
                    [WBVAppManager.sharedManager saveBackgroundSetting:!enable forVApp:vapp];
                    [SVProgressHUD showErrorWithStatus:error.localizedDescription];
                    return;
                }

                /**
                 canOn值说明：
                    0：服务器决定关；
                    1：服务器决定开；
                    2：服务器决定开并弹不稳定提示弹窗（app下架）;
                 */
                id canOn = json[@"canOn"];  // 服务器决定的开关结果
                id tip = json[@"tip"];  // 开关结果提示语
                id route = json[@"route"];  // 开关操作后执行的路由
                if (!canOn || [canOn isKindOfClass:[NSNull class]]) return;
                NSInteger canOnNumber = [(NSNumber *)canOn integerValue];
                vapp.featureStatusInfo.isNotificationSwitchOn = (canOnNumber != 0);
                [WBVAppManager.sharedManager saveBackgroundSetting:vapp.featureStatusInfo.isNotificationSwitchOn forVApp:vapp];
                if (setSwitch) setSwitch(vapp.featureStatusInfo.isNotificationSwitchOn, YES);
                if (enable && vapp.featureStatusInfo.isNotificationSwitchOn) {
                    [self consumeUsageOnceForBenefitBit:WBUserBenefitNotification];
                }

                if (enable) {   // 开启
                    if (canOnNumber == 2) {
                        UIAlertController *alertVC = [UIAlertController alertControllerWithTitle:@"温馨提示" message:@"当前版本【消息推送】尚不稳定\n如需帮助，请联系客服咨询" preferredStyle:UIAlertControllerStyleAlert];
                        [alertVC addAction:[UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil]];
                        UIViewController *vc = presenter ?: [WBAppManager getUIApplicationRootViewController];
                        [vc presentViewController:alertVC animated:YES completion:nil];
                    } else if (tip && ![tip isKindOfClass:[NSNull class]]) {
                        NSString *trimmedTip = [[tip stringValue] stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceCharacterSet]];
                        if (trimmedTip.length > 0) {
                            if (canOnNumber == 1) [SVProgressHUD showSuccessWithStatus:trimmedTip]; else [SVProgressHUD showErrorWithStatus:trimmedTip];
                        }
                    }
                } else if (tip && ![tip isKindOfClass:[NSNull class]]) {
                    NSString *trimmedTip = [[tip stringValue] stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceCharacterSet]];
                    if (trimmedTip.length > 0) {
                        if (canOnNumber == 0) [SVProgressHUD showSuccessWithStatus:trimmedTip]; else [SVProgressHUD showErrorWithStatus:trimmedTip];
                    }
                }

                if (route && ![route isKindOfClass:[NSNull class]] && [route isKindOfClass:[NSString class]]) {
                    NSURL *routeUrl = [NSURL URLWithString:(NSString *)route];
                    [[WBRouteManager sharedManager] performRoute:routeUrl sourceInterface:@"user/notifyConnect"];
                }
            });
        }];
    };

    void (^showEnableAlert)(void (^)(void)) = ^(void (^confirmAction)(void)) {
        [[UNUserNotificationCenter currentNotificationCenter] getNotificationSettingsWithCompletionHandler:^(UNNotificationSettings *settings) {
            dispatch_async(dispatch_get_main_queue(), ^{
                if (settings.authorizationStatus == UNAuthorizationStatusAuthorized) {
                    confirmAction();
                } else if (settings.authorizationStatus == UNAuthorizationStatusNotDetermined) {
                    [[UNUserNotificationCenter currentNotificationCenter] requestAuthorizationWithOptions:UNAuthorizationOptionAlert | UNAuthorizationOptionSound completionHandler:^(BOOL granted, NSError *error) {
                        dispatch_async(dispatch_get_main_queue(), ^{
                            if (granted) {
                                confirmAction();
                            } else {
                                vapp.featureStatusInfo.isNotificationSwitchOn = NO;
                                if (setSwitch) setSwitch(NO, YES);
                            }
                        });
                    }];
                } else {
                    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"温馨提示" message:@"打开消息推送需要在系统设置中开启通知权限" preferredStyle:UIAlertControllerStyleAlert];
                    [alert addAction:[UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleCancel handler:^(UIAlertAction *action) {}]];
                    [alert addAction:[UIAlertAction actionWithTitle:@"去开启" style:UIAlertActionStyleDefault handler:^(UIAlertAction *action) {
                        dispatch_async(dispatch_get_main_queue(), ^{
                            NSURL *url = [NSURL URLWithString:UIApplicationOpenSettingsURLString];
                            if ([[UIApplication sharedApplication] canOpenURL:url]) {
                                [[UIApplication sharedApplication] openURL:url options:@{} completionHandler:nil];
                            }
                        });
                    }]];
                    UIViewController *vc = presenter ?: [WBAppManager getUIApplicationRootViewController];
                    [vc presentViewController:alert animated:YES completion:nil];
                    vapp.featureStatusInfo.isNotificationSwitchOn = NO;
                    if (setSwitch) setSwitch(NO, YES);
                }
            });
        }];
    };

    void (^showDisableAlert)(void (^)(void)) = ^(void (^confirmAction)(void)) {
        UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"是否关闭消息推送" message:@"关闭后将出现短暂延迟，请稍候" preferredStyle:UIAlertControllerStyleAlert];
        [alert addAction:[UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleCancel handler:^(UIAlertAction * _Nonnull action) {
            dispatch_async(dispatch_get_main_queue(), ^{
                vapp.featureStatusInfo.isNotificationSwitchOn = YES;
                if (setSwitch) setSwitch(YES, YES);
            });
        }]];
        [alert addAction:[UIAlertAction actionWithTitle:@"关闭" style:UIAlertActionStyleDestructive handler:^(UIAlertAction * _Nonnull action) { confirmAction(); }]];
        UIViewController *vc = presenter ?: [WBAppManager getUIApplicationRootViewController];
        [vc presentViewController:alert animated:YES completion:nil];
    };

    void (^proceedOnWithVerification)(void) = ^{ showEnableAlert(^{ toggleNotificationBlock(YES); }); };
    void (^proceedOffWithVerification)(void) = ^{ showDisableAlert(^{ toggleNotificationBlock(NO); }); };

    if (vapp.featureStatusInfo.isLockSwitchOn) {
        WBPasswordViewController *passwordVc = [WBPasswordViewController new];
        passwordVc.firstSet = FALSE;
        passwordVc.vapp = vapp;
        passwordVc.type = WBPasswordViewControllerTypeEntry;
        passwordVc.bioEnable = true;
        passwordVc.successBlock = ^{ isTurningOn ? proceedOnWithVerification() : proceedOffWithVerification(); };
        passwordVc.failBlock = ^{ if (setSwitch) setSwitch(!isTurningOn, YES); };
        [presenter.navigationController pushViewController:passwordVc animated:YES];
    } else {
        isTurningOn ? proceedOnWithVerification() : proceedOffWithVerification();
    }
}


// 安全锁开关 (首页/设置页复用)
- (void)toggleLockForVapp:(WBVAppModel *)vapp
                 presenter:(UIViewController *)presenter
                switchCell:(nullable WBSettingIconSwitchCell *)cell
                 setSwitch:(void(^)(BOOL on, BOOL animated))setSwitch {
    if (WBVAppManager.sharedManager.myApps.count <= 0) {
        if (setSwitch) setSwitch(NO, YES);
        UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"提醒" message:@"请先安装您的第一个应用后再来开启吧" preferredStyle:UIAlertControllerStyleAlert];
        [alert addAction:[UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil]];
        UIViewController *vc = presenter ?: [WBAppManager getUIApplicationRootViewController];
        [vc presentViewController:alert animated:YES completion:nil];
        return;
    }

    BOOL isTurningOn = !vapp.featureStatusInfo.isLockSwitchOn;
    BOOL canSwitch = [self handleSwitchBenefitFunction:WBUserBenefitLock target:isTurningOn vapp:vapp];
    if (!canSwitch) {
        if (setSwitch) setSwitch(NO, YES);
        return;
    }

    if (isTurningOn) {
        WBTurnOnPasswordAnimationViewController *turnOnPasswordVC = [[WBTurnOnPasswordAnimationViewController alloc] initWithVapp:vapp];
        turnOnPasswordVC.settingIconSwitchCell = cell;
        turnOnPasswordVC.failBlock = ^{ if (setSwitch) setSwitch(NO, YES); };
        [presenter.navigationController pushViewController:turnOnPasswordVC animated:true];
    } else {
        if (vapp.featureStatusInfo.isLockSwitchOn) {
            WBPasswordViewController *passwordVc = [WBPasswordViewController new];
            passwordVc.firstSet = FALSE;
            passwordVc.vapp = vapp;
            passwordVc.type = WBPasswordViewControllerTypeEntry;
            passwordVc.successBlock = ^{
                vapp.featureStatusInfo.isLockSwitchOn = NO;
                [WBVAppManager.sharedManager saveLockStatusForVApp:vapp];
                [SVProgressHUD showSuccessWithStatus:@"已关闭安全锁"];
                if (setSwitch) setSwitch(NO, YES);
            };
            passwordVc.failBlock = ^{ if (setSwitch) setSwitch(YES, YES); };
            [presenter.navigationController pushViewController:passwordVc animated:YES];
        } else {
            [SVProgressHUD showErrorWithStatus:@"状态异常，请重试"];
        }
    }
}


