- (NSArray<NSString *> *)findFeatureIconAndNameWithCodeName:(NSString *)codeName {
    for (WBVIPFeatureModel *feature in self.features) {
        if ([feature.code_name isEqualToString:codeName]) {
            return @[feature.icon_v1, feature.icon_v3_svip, feature.name];
        }
    }
    return @[@"", @"", @""];
}

- (BOOL)judgeFeatureCouldSelectWithCodeName:(NSString *)codeName {
    NSUInteger benefit = WBSettingManager.sharedManager.Benefit;
    if ([codeName isEqualToString:@"notification"]) return (benefit & WBUserBenefitNotification) != 0;
    if ([codeName isEqualToString:@"lock"]) return (benefit & WBUserBenefitLock) != 0;
    if ([codeName isEqualToString:@"disguise"]) return (benefit & WBUserBenefitDisguise) != 0;
    if ([codeName isEqualToString:@"pretense"]) return (benefit & WBUserBenefitPretense) != 0;
    if ([codeName isEqualToString:@"oneclick"]) return (benefit & WBUserBenefitOneClick) != 0;
    return NO;
}

- (NSArray<NSString *> *)finalResultIconAndNameWithCodeName:(NSString *)codeName {
    NSArray<NSString *> *resultArray = [self findFeatureIconAndNameWithCodeName:codeName];
    BOOL couldSelect = [self judgeFeatureCouldSelectWithCodeName:codeName];
    if (!couldSelect) {
        NSString *cannotSelectFeatureName = [NSString stringWithFormat:@"%@（SVIP专享）", resultArray[2]];
        return @[resultArray[0], cannotSelectFeatureName];
    }
    return @[resultArray[1], resultArray[2]];
}

